SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

DROP TRIGGER IF EXISTS tbiu_sc_fund_detail ON sc_fund_detail CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_fund_detail() RETURNS trigger AS $BODY$
BEGIN

    --//--Auto
    if pka.auto_seqno then
        if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then 
            select max(seq_no) into STRICT NEW.seq_no
            from sc_fund_detail 
            where fund_loan_no = NEW.fund_loan_no 
            and loan_type  = NEW.loan_type;
            NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
        end if;
    end if;

    --//-- Default
    if coalesce(OLD.fund_loan_no::text, '') = '' and (NEW.fund_loan_no IS NOT NULL AND NEW.fund_loan_no::text <> '') then
        if  pka.auto_entry then
           -- เวลาที่แก้ไขล่าสุด(บังคับ)
          NEW.user_id := current_setting('app.login_id', true);
          NEW.user_date := statement_timestamp();
          NEW.branch_id := current_setting('app.login_br', true);
          NEW.workingday := statement_timestamp();
       end if;
   end if;

   if coalesce(NEW.status::text, '') = '' then NEW.status :='0';end if;

RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
-- REVOKE ALL ON FUNCTION trigger_fct_tbiu_sc_fund_detail() FROM PUBLIC;

CREATE TRIGGER tbiu_sc_fund_detail
	BEFORE INSERT OR UPDATE ON sc_fund_detail FOR EACH ROW
	EXECUTE PROCEDURE trigger_fct_tbiu_sc_fund_detail();

